function:src/openhuman/memory_sync/composio/providers/notion/source.rs:page_ids
                .into_iter()
                .map(|page_id| {
                    let ctx = &ctx;
                    async move {
                        match ctx
                            .execute(
                                ACTION_GET_PAGE_MARKDOWN,
                                Some(json!({ "page_id": &page_id })),
                            )
                            .await
                        {
                            Ok(resp) if resp.successful => {
                                let markdown = sync::extract_page_markdown(&resp.data);
                                if markdown.is_none() {
                                    tracing::warn!(
                                        page_id = %page_id,
                                        "[composio:notion] GET_PAGE_MARKDOWN returned no \
                                         markdown field — metadata-only fallback"
                                    );
                                }
                                markdown
                            }
                            Ok(resp) => {
                                tracing::warn!(
                                    page_id = %page_id,
                                    error = ?resp.error,
                                    "[composio:notion] GET_PAGE_MARKDOWN failed — \
                                     metadata-only fallback"
                                );
                                None
                            }
                            Err(e) => {
                                tracing::warn!(
                                    page_id = %page_id,
                                    error = %e,
                                    "[composio:notion] GET_PAGE_MARKDOWN execute error — \
                                     metadata-only fallback"
                                );
                                None
                            }
                        }
                    }
                }).collect

